import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Terminal from './components/Terminal';
import Backups from './components/Backups';
import AuditLogs from './components/AuditLogs';
import Settings from './components/Settings';

function App() {
  const [currentPage, setCurrentPage] = useState('dashboard');
  const [theme, setTheme] = useState(() => {
    const saved = localStorage.getItem('lorcgr-theme');
    return saved ? JSON.parse(saved) : { mode: 'dark', primaryColor: 'blue' };
  });

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme.mode);
    document.documentElement.setAttribute('data-primary', theme.primaryColor);
    if (theme.mode === 'dark') {
      document.body.classList.add('bg-gray-900');
      document.body.classList.remove('bg-gray-100');
    } else {
      document.body.classList.add('bg-gray-100');
      document.body.classList.remove('bg-gray-900');
    }
  }, [theme]);

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard': return <Dashboard />;
      case 'inventory': return <Inventory />;
      case 'terminal': return <Terminal />;
      case 'backups': return <Backups />;
      case 'audit': return <AuditLogs />;
      case 'settings': return <Settings />;
      default: return <Dashboard />;
    }
  };

  const pageTitle = {
    dashboard: 'Dashboard', inventory: 'Inventário de Dispositivos', terminal: 'Terminal SSH',
    backups: 'Gerenciamento de Backups', audit: 'Logs de Auditoria', settings: 'Configurações'
  };

  return (
    <div className={'flex h-screen ' + (theme.mode === 'dark' ? 'bg-gray-900' : 'bg-gray-100')}>
      <Sidebar currentPage={currentPage} setCurrentPage={setCurrentPage} />
      <main className={'flex-1 overflow-auto ' + (theme.mode === 'dark' ? 'bg-gray-900' : 'bg-gray-100')}>
        <header className={(theme.mode === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200') + ' border-b px-6 py-4'}>
          <div className="flex items-center justify-between">
            <h1 className={'text-xl font-semibold ' + (theme.mode === 'dark' ? 'text-white' : 'text-gray-900')}>{pageTitle[currentPage]}</h1>
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-blue-600 rounded-full flex items-center justify-center"><span className="text-white text-sm font-medium">A</span></div>
              <span className={'text-sm ' + (theme.mode === 'dark' ? 'text-gray-300' : 'text-gray-700')}>Admin</span>
            </div>
          </div>
        </header>
        <div className="p-6">{renderPage()}</div>
      </main>
    </div>
  );
}

export default App;
